```typescript
import { Module } from '@nestjs/common';
import { ConfigModule } from '@nestjs/config';

@Module({
  imports: [
    ConfigModule.forRoot({
      envFilePath: process.env.NODE_ENV === 'production' 
        ? '.env.production' 
        : '.env.development',
      isGlobal: true,
    }),
  ],
})
export class AppModule {}
```
On peut aussi utiliser un tableau pour charger plusieurs fichiers : `envFilePath: ['.env', '.env.local']`

```typescript
import * as Joi from 'joi';

ConfigModule.forRoot({
  validationSchema: Joi.object({
    PORT: Joi.number().min(3000).max(9000).default(3000),
    DB_HOST: Joi.string().required(),
    DB_PORT: Joi.number().min(1).max(65535).default(5432),
    JWT_SECRET: Joi.string().min(32).required(),
    NODE_ENV: Joi.string().valid('development', 'staging', 'production').default('development'),
  }),
})
```
Le `validationSchema` lance une erreur au démarrage si une variable requise est manquante ou invalide.

```typescript
import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class DatabaseConfigService {
  constructor(private configService: ConfigService) {}

  getHost(): string {
    return this.configService.get<string>('DB_HOST');
  }

  getPort(): number {
    return this.configService.get<number>('DB_PORT');
  }

  getUsername(): string {
    return this.configService.get<string>('DB_USERNAME');
  }

  getPassword(): string {
    return this.configService.get<string>('DB_PASSWORD');
  }

  getDatabase(): string {
    return this.configService.get<string>('DB_NAME');
  }
}
```

```typescript
// Dans le fichier de configuration ou app.module.ts
if (process.env.NODE_ENV !== 'production') {
  const configService = app.get(ConfigService);
  console.log('📁 Variables chargées :');
  console.log('- PORT:', configService.get('PORT'));
  console.log('- DB_HOST:', configService.get('DB_HOST'));
  console.log('- Fichier .env utilisé:', process.env.NODE_ENV === 'development' ? '.env.development' : '.env');
}
```

Autre méthode : utiliser l'option `expandVariables` et logger les noms des variables sans leurs valeurs sensibles. On peut aussi créer une route admin (protégée) qui expose les noms des variables définies, mais pas leurs valeurs en production.
